insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('signs-1', 'signs', 'WARS AND RUMORS OF WARS', 'Symptom of a troubled world preceding the Second Advent, mentioned in the Olivet discourse.', 'Olivet discourse symptom: nations rise against nations before the end.', 'Matthew 24:6', 'And ye shall hear of wars and rumours of wars: see that ye be not troubled: for all these things must come to pass, but the end is not yet.', 'As the end approaches, international conflicts and political instability serve as reminders that this world is temporary and the return of Christ is near.', 0),
  ('signs-2', 'signs', 'FALSE PROPHETS', 'Deceivers who will arise to show great signs and wonders, attempting to mislead even the elect.', 'Matthew 24 warns these deceivers may show wonders to mislead the elect.', 'Matthew 24:24', 'For there shall arise false Christs, and false prophets, and shall shew great signs and wonders; insomuch that, if it were possible, they shall deceive the very elect.', 'Spiritual deception will reach its climax before the end. The only safeguard against the delusions of the enemy is a deep, personal knowledge of God''s Word.', 1),
  ('signs-3', 'signs', 'PERSECUTION', 'The trial God''s people will face for keeping His commandments and holding the testimony of Jesus.', 'Hated of all nations for His name — Matthew 24:9 affliction.', 'Matthew 24:9', 'Then shall they deliver you up to be afflicted, and shall kill you: and ye shall be hated of all nations for my name''s sake.', 'Opposition from the world reveals the true character of our faith and purifies the church, preparing believers to stand in the final conflict.', 2),
  ('signs-4', 'signs', 'PREACHING THE GOSPEL', 'The ultimate gospel task that must be finished in all the world as a witness before the end.', 'Must reach every nation as a witness — then the end arrives.', 'Matthew 24:14', 'And this gospel of the kingdom shall be preached in all the world for a witness unto all nations; and then shall the end come.', 'The end will not come until everyone has had a fair opportunity to hear and accept the message of salvation. We are called to cooperate in this great work.', 3),
  ('shaking-1', 'shaking', 'SHAKING', 'A testing time among God''s people where the superficial are separated from the faithful.', 'Hebrews 12:27 — only what cannot be shaken will remain.', 'Hebrews 12:27', 'And this word, Yet once more, signifieth the removing of those things that are shaken, as of things that are made, that those things which cannot be shaken may remain.', 'A great sifting occurs as trials and false doctrines test the church. Only those anchored in truth and genuine experience will stand.', 0),
  ('shaking-2', 'shaking', 'STRAIGHT TESTIMONY', 'The direct counsel to the Laodiceans that rouses the church and causes the shaking.', 'Laodicean rebuke: ''As many as I love, I rebuke and chasten.''', 'Revelation 3:19', 'As many as I love, I rebuke and chasten: be zealous therefore, and repent.', 'The True Witness''s testimony is a call to repentance and spiritual revival, dividing those who accept it from those who reject it in self-righteousness.', 1),
  ('shaking-3', 'shaking', 'REJECTION OF TRUTH', 'The choice to compromise or turn away from Bible doctrines, leading to spiritual darkness during sifting.', 'They received not the love of the truth — 2 Thessalonians 2:10.', '2 Thessalonians 2:10', 'And with all deceivableness of unrighteousness in them that perish; because they received not the love of the truth, that they might be saved.', 'Compromise with the world and neglected truth leaves the soul vulnerable to the strong delusions of the last days.', 2),
  ('shaking-4', 'shaking', 'SIFTING', 'The purification process where the chaff of worldly members is blown away from the wheat of God''s church.', 'Amos 9:9 — sifted like corn; not one grain falls to the earth.', 'Amos 9:9', 'For, lo, I will command, and I will sift the house of Israel among all nations, like as corn is sifted in a sieve, yet shall not the least grain fall upon the earth.', 'God permits trials to cleanse His church so that she may be presented pure, united, and ready to receive the power of the Latter Rain.', 3),
  ('latter-rain-1', 'latter-rain', 'LATTER RAIN', 'The final outpouring of the Holy Spirit to ripen the harvest and empower the loud cry.', 'Joel 2:23 — former rain moderately, latter rain at harvest end.', 'Joel 2:23', 'Be glad then, ye children of Zion, and rejoice in the LORD your God: for he hath given you the former rain moderately, and he will cause to come down for you the rain, the former rain, and the latter rain in the first month.', 'Just as the early rain started the church at Pentecost, the latter rain will finish God''s work on earth with spectacular spiritual power.', 0),
  ('latter-rain-2', 'latter-rain', 'PENTECOST', 'The historical outpouring of the Holy Spirit that empowered the early Christian church.', 'Acts 2 — the early rain that launched the apostolic church.', 'Acts 2:4', 'And they were all filled with the Holy Ghost, and began to speak with other tongues, as the Spirit gave them utterance.', 'Pentecost was the ''early rain'' of the Spirit. The latter rain will be even more abundant, covering the whole earth with the glory of God.', 1),
  ('latter-rain-3', 'latter-rain', 'REFRESHING', 'Times of spiritual reviving and preparation that come from the presence of the Lord.', 'Acts 3:19 — sins blotted out when refreshing comes from His presence.', 'Acts 3:19', 'Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord.', 'Before we can receive the fullness of the Holy Spirit, we must experience personal revival, repentance, and the blotting out of sins.', 2),
  ('latter-rain-4', 'latter-rain', 'HOLY SPIRIT', 'The Divine Agent of the latter rain outpouring, promised by Christ to guide into all truth.', 'Zechariah 10:1 — ask the LORD for rain in the time of the latter rain.', 'Zechariah 10:1', 'Ask ye of the LORD rain in the time of the latter rain; so the LORD shall make bright clouds, and give them showers of rain, to every one grass in the field.', 'We must actively pray for the Holy Spirit daily, preparing our vessels to be filled with the final shower of divine grace.', 3),
  ('loud-cry-1', 'loud-cry', 'LOUD CRY', 'The final worldwide warning message that swells from the third angel''s message.', 'Revelation 18:1 — the earth lightened with His glory.', 'Revelation 18:1', 'And after these things I saw another angel come down from heaven, having great power; and the earth was lightened with his glory.', 'An urgent, powerful call that illuminates the entire earth, exposing deception and presenting God''s final invitation of mercy to all mankind.', 0),
  ('loud-cry-2', 'loud-cry', 'THREE ANGELS', 'The special three-fold message of Revelation 14 containing God''s final warning of judgment and worship.', 'Revelation 14''s threefold final warning of judgment and worship.', 'Revelation 14:6-7', 'And I saw another angel fly in the midst of heaven, having the everlasting gospel to preach unto them that dwell on the earth... Saying with a loud voice, Fear God, and give glory to him; for the hour of his judgment is come...', 'This message calls humanity back to worshipping the Creator, warns against false worship, and identifies the faithful who keep God''s commandments.', 1),
  ('loud-cry-3', 'loud-cry', 'BABYLON IS FALLEN', 'The second angel''s declaration that the corrupt world religious systems have departed from truth.', 'Second angel of Revelation 14 — great city fallen twice over.', 'Revelation 14:8', 'And there followed another angel, saying, Babylon is fallen, is fallen, that great city, because she made all nations drink of the wine of the wrath of her fornication.', 'Babylon represents confused, compromised religious bodies that have united with the state. God warns that her spiritual fall is complete.', 2),
  ('loud-cry-4', 'loud-cry', 'OUT OF HER MY PEOPLE', 'The urgent call of the fourth angel to leave Babylon in order to avoid her plagues.', 'Revelation 18:4 — leave before you share in her sins and plagues.', 'Revelation 18:4', 'And I heard another voice from heaven, saying, Come out of her, my people, that ye be not partakers of her sins, and that ye receive not of her plagues.', 'God still has sincere followers within compromised religious systems. This is His loving, final appeal for them to walk in full Biblical truth.', 3),
  ('seal-of-god-1', 'seal-of-god', 'SEAL OF GOD', 'God''s sign of authority, ownership, and protection placed upon the foreheads of the faithful.', 'Revelation 7:3 — sealed in the forehead before harm to earth.', 'Revelation 7:3', 'Saying, Hurt not the earth, neither the sea, nor the trees, till we have sealed the servants of our God in their foreheads.', 'The seal of God is a settling into the truth, both intellectually and spiritually, so that believers cannot be moved.', 0),
  ('seal-of-god-2', 'seal-of-god', 'SABBATH', 'The seventh-day memorial of creation which serves as the core test of allegiance and the sign of the Seal.', 'Ezekiel 20:12 — sign between God and His people as Creator.', 'Ezekiel 20:12', 'Moreover also I gave them my sabbaths, to be a sign between me and them, that they might know that I am the LORD that sanctify them.', 'As the commandment identifying God as Creator and Sovereign, the Sabbath is the ultimate test of loyalty in the final crisis.', 1),
  ('seal-of-god-3', 'seal-of-god', 'SUNDAY LAW', 'The legislative decree that enforces false worship, establishing the Mark of the Beast in contrast to God''s Sabbath.', 'Legislated false worship day enforced by civil power.', 'Revelation 13:16', 'And he causeth all, both small and great, rich and poor, free and bond, to receive a mark in their right hand, or in their foreheads.', 'A legislative decree that forces individuals to choose between obeying human laws or the immutable, holy law of God.', 2),
  ('seal-of-god-4', 'seal-of-god', 'MARK OF THE BEAST', 'The sign of allegiance to the beast power, received when one knowingly rejects God''s Sabbath for a human substitute.', 'Revelation 13:17 — required for buying and selling.', 'Revelation 13:17', 'And that no man might buy or sell, save he that had the mark, or the name of the beast, or the number of his name.', 'Receiving the mark represents submission to earthly powers over God. It stands in direct, active opposition to the Seal of God.', 3)
insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('time-of-trouble-1', 'time-of-trouble', 'CLOSE OF PROBATION', 'The solemn moment when Christ finishes His intercessory sanctuary ministry and the destiny of all is fixed.', 'Revelation 22:11 — character fixed; no mediator remains.', 'Revelation 22:11', 'He that is unjust, let him be unjust still: and he which is filthy, let him be filthy still: and he that is righteous, let him be righteous still: and he that is holy, let him be holy still.', 'When the intercession of Jesus ends, the door of mercy is closed forever. The righteous remain holy, and the wicked remain wicked.', 0),
  ('time-of-trouble-2', 'time-of-trouble', 'TIME OF TROUBLE', 'A period of unprecedented global crisis and distress that occurs after probation closes.', 'Daniel 12:1 — trouble such as never was since there was a nation.', 'Daniel 12:1', 'And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation...', 'Without an intercessor, the earth experiences the full weight of human rebellion and plagues, but God preserves His faithful ones.', 1),
  ('time-of-trouble-3', 'time-of-trouble', 'JACOBS TROUBLE', 'The intense spiritual wrestling and anguish experienced by the saints as they plead for deliverance.', 'Jeremiah 30:7 — Jacob''s anguish, but saved out of it.', 'Jeremiah 30:7', 'Alas! for that day is great, so that none is like it: it is even the time of Jacob''s trouble, but he shall be saved out of it.', 'Believers will review their lives, deeply repenting of any sin, and holding on to God by faith alone, refusing to let Him go.', 2),
  ('time-of-trouble-4', 'time-of-trouble', 'DEATH DECREE', 'The final earthly decree dictating that those who refuse to worship the image of the beast should be killed.', 'Revelation 13:15 — image speaks; refusers face execution.', 'Revelation 13:15', 'And he had power to give life unto the image of the beast, that the image of the beast should both speak, and cause that as many as would not worship the image of the beast should be killed.', 'A decree will be passed to execute God''s commandment-keeping people. But God will step in to deliver His saints.', 3),
  ('second-coming-1', 'second-coming', 'SECOND COMING', 'The glorious, literal, and visible return of Jesus Christ in the clouds of heaven.', 'Titus 2:13 — the blessed hope and glorious appearing.', 'Titus 2:13', 'Looking for that blessed hope, and the glorious appearing of the great God and our Saviour Jesus Christ.', 'The climax of the Christian hope. Jesus returns not in secret, but in supreme majesty, visible to every eye.', 0),
  ('second-coming-2', 'second-coming', 'EASTERN SKY', 'The direction where a small cloud, about half the size of a man''s hand, first appears to the waiting saints.', 'Matthew 24:30 — sign of the Son of man seen in heaven''s clouds.', 'Matthew 24:30', 'And then shall appear the sign of the Son of man in heaven: and then shall all the tribes of the earth mourn, and they shall see the Son of man coming in the clouds of heaven with power and great glory.', 'A small, dark cloud in the east is the sign of Christ''s approach. As it draws near, it becomes a great, brilliant cloud of glory.', 1),
  ('second-coming-3', 'second-coming', 'RESURRECTION', 'The miraculous awakening of the dead in Christ at the sound of the trumpet.', '1 Thessalonians 4:16 — trumpet; dead in Christ rise first.', '1 Thessalonians 4:16', 'For the Lord himself shall descend from heaven with a shout, with the voice of the archangel, and with the trump of God: and the dead in Christ shall rise first.', 'Graves are opened worldwide, and the sleeping saints are raised with immortal bodies, reunited with their loved ones.', 2),
  ('second-coming-4', 'second-coming', 'TRANSLATION', 'The instantaneous change of the living righteous from mortality to immortality, caught up to meet the Lord.', '1 Thessalonians 4:17 — living saints caught up to meet Him in the air.', '1 Thessalonians 4:17', 'Then we which are alive and remain shall be caught up together with them in the clouds, to meet the Lord in the air: and so shall we ever be with the Lord.', 'The living faithful are transformed without seeing death, joining the resurrected saints to meet Jesus in the air.', 3),
  ('new-earth-1', 'new-earth', 'REMNANT', 'The end-time group of believers who keep the commandments of God and have the testimony of Jesus.', 'Revelation 12:17 — keep commandments and hold testimony of Jesus.', 'Revelation 12:17', 'And the dragon was wroth with the woman, and went to make war with the remnant of her seed, which keep the commandments of God, and have the testimony of Jesus Christ.', 'The final fraction of God''s church, characterized by loyalty to His law and possession of the prophetic gift.', 0),
  ('new-earth-2', 'new-earth', 'NEW EARTH', 'God''s restored, Edenic world recreated from the ashes of sin for the eternal home of the redeemed.', 'Revelation 21:1 — first heaven and earth passed away.', 'Revelation 21:1', 'And I saw a new heaven and a new earth: for the first heaven and the first earth were passed away; and there was no more sea.', 'Sin is permanently erased. The earth is restored to its original beauty, and God dwells personally with His people.', 1),
  ('new-earth-3', 'new-earth', 'NEW JERUSALEM', 'The majestic holy city that descends from God out of heaven to become the capital of the New Earth.', 'Revelation 21:2 — holy city prepared as a bride adorned.', 'Revelation 21:2', 'And I John saw the holy city, new Jerusalem, coming down from God out of heaven, prepared as a bride adorned for her husband.', 'The capital city of the saved, filled with the glory of God, built of gold and precious stones, where Christ and His saints reside.', 2),
  ('new-earth-4', 'new-earth', 'NO MORE DEATH', 'The glorious state of eternity where pain, sorrow, crying, and physical expiry are completely banished.', 'Revelation 21:4 — God wipes every tear; pain and death are gone.', 'Revelation 21:4', 'And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away.', 'The ultimate triumph of Christ''s redemption. Every trace of the curse of sin is wiped away, and eternal joy begins.', 3),
  ('judgment-1', 'judgment', 'INVESTIGATIVE JUDGMENT', 'The heavenly tribunal where records are examined before Christ''s return to earth.', 'Daniel 7:9-10 — books opened; the Ancient of days presides.', 'Daniel 7:9-10', 'I beheld till the thrones were cast down, and the Ancient of days did sit... thousand thousands ministered unto him, and ten thousand times ten thousand stood before him: the judgment was set, and the books were opened.', 'Before Christ returns as King, heaven conducts a review of every life. This judgment vindicates God''s character and confirms who is ready for eternity.', 0),
  ('judgment-2', 'judgment', 'PRE ADVENT JUDGMENT', 'Divine review that must finish before the Second Coming, not after it.', '2300-day prophecy of Daniel 8:14 points to this cleansing era.', 'Daniel 8:14', 'And he said unto me, Unto two thousand and three hundred days; then shall the sanctuary be cleansed.', 'The Bible places judgment before the Advent. God''s people are judged while probation still lingers, so the living may be prepared to meet Christ.', 1),
  ('judgment-3', 'judgment', 'BLOT OUT SINS', 'The act of removing confessed transgressions from heavenly records during judgment.', 'Acts 3:19 links repentance with sins being blotted out.', 'Acts 3:19', 'Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord.', 'Through faith in Christ, forgiven sins are erased from the books of heaven. This is the gospel assurance that motivates holy living.', 2),
  ('judgment-4', 'judgment', 'CLEANSING OF SANCTUARY', 'The antitypical Day of Atonement when the heavenly temple is purified from sin''s record.', 'Hebrews 8:1-2 — Christ ministers in the true tabernacle pitched by the Lord.', 'Hebrews 9:23', 'It was therefore necessary that the patterns of things in the heavens should be purified with these; but the heavenly things themselves with better sacrifices than these.', 'Just as the earthly sanctuary was cleansed on the Day of Atonement, Christ now removes sin''s defilement from the heavenly sanctuary through His blood.', 3),
  ('deceptions-1', 'deceptions', 'STRONG DELUSION', 'God permits believing a lie when truth is rejected — a final test of loyalty.', '2 Thessalonians 2:11 — sent because they received not the love of the truth.', '2 Thessalonians 2:11', 'And for this cause God shall send them strong delusion, that they should believe a lie.', 'When humanity refuses to love truth, God withdraws restraining grace. The result is widespread deception that only Bible students will discern.', 0),
  ('deceptions-2', 'deceptions', 'SPIRITUALISM', 'Satan''s end-time masquerade through spirits and signs imitating the dead and divine.', 'Revelation 16:13-14 — three unclean spirits like frogs from dragon, beast, false prophet.', 'Revelation 16:14', 'For they are the spirits of devils, working miracles, which go forth unto the kings of the earth and of the whole world, to gather them to the battle of that great day of God Almighty.', 'Spiritualism will unite the world through miraculous displays. It is one of Satan''s most successful tools to replace faith in Scripture with experience and emotion.', 1),
  ('deceptions-3', 'deceptions', 'UNCLEAN SPIRITS', 'Demonic agents released to perform signs and unite the world for the final conflict.', 'Revelation 16:13 — frog-like spirits from the satanic trinity.', 'Revelation 16:13', 'And I saw three unclean spirits like frogs come out of the mouth of the dragon, and out of the mouth of the beast, and out of the mouth of the false prophet.', 'These spirits perform wonders that deceive rulers and peoples alike, preparing the world to oppose God and His faithful remnant.', 2),
  ('deceptions-4', 'deceptions', 'ARMAGEDDON', 'The symbolic gathering place for the final worldwide showdown between truth and rebellion.', 'Revelation 16:16 — kings gathered to the place called in Hebrew Armageddon.', 'Revelation 16:16', 'And he gathered them together into a place called in the Hebrew tongue Armageddon.', 'Armageddon is not a literal valley battle alone, but the climactic conflict of the ages where all humanity chooses sides for or against God.', 3)
insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('daniel-image-1', 'daniel-image', 'GREAT IMAGE', 'The enormous statue of mixed metals that filled the king''s dream of successive world empires.', 'Daniel 2:31 — a terrible, excellent image stood before the king.', 'Daniel 2:31', 'Thou, O king, sawest, and behold a great image. This great image, whose brightness was excellent, stood before thee; and the form thereof was terrible.', 'God revealed the outline of history through a single dream-image, showing that earthly kingdoms rise and fall under His sovereignty.', 0),
  ('daniel-image-2', 'daniel-image', 'HEAD OF GOLD', 'The top of the image representing Babylon, the first kingdom in the prophetic succession.', 'Daniel 2:38 — ''Thou art this head of gold.''', 'Daniel 2:38', 'And wheresoever the children of men dwell, the beasts of the field and the fowls of the heaven hath he given into thine hand, and hath made thee ruler over them all. Thou art this head of gold.', 'Babylon''s glory is symbolized by gold — yet even the head of gold is temporary before the everlasting kingdom of God.', 1),
  ('daniel-image-3', 'daniel-image', 'FEET OF IRON AND CLAY', 'The divided toes of the image showing a mixed, unstable end-time political order.', 'Daniel 2:41 — feet and toes of iron mixed with miry clay.', 'Daniel 2:41', 'And whereas thou sawest the feet and toes, part of potters'' clay, and part of iron, the kingdom shall be divided; but there shall be in it of the strength of the iron, forasmuch as thou sawest the iron mixed with miry clay.', 'The final phase of earthly power is strong yet brittle — never fully united until Christ returns.', 2),
  ('daniel-image-4', 'daniel-image', 'STONE CUT WITHOUT HANDS', 'The supernatural stone that smashes the image and becomes a mountain filling the whole earth.', 'Daniel 2:34 — stone cut out without hands smote the image.', 'Daniel 2:34', 'Thou sawest till that a stone was cut out without hands, which smote the image upon his feet that were of iron and clay, and brake them to pieces.', 'Christ''s kingdom is not of human origin. It ends all earthly empires and fills the earth with righteousness forever.', 3),
  ('daniel-beasts-1', 'daniel-beasts', 'FOUR GREAT BEASTS', 'Four diverse animals that came up from the sea, representing four kings or kingdoms.', 'Daniel 7:3 — four great beasts came up from the sea.', 'Daniel 7:3', 'And four great beasts came up from the sea, diverse one from another.', 'From the turbulent sea of nations rise successive empires — a second line of prophecy paralleling the metallic image.', 0),
  ('daniel-beasts-2', 'daniel-beasts', 'LION WITH EAGLES WINGS', 'The first beast of Daniel 7, swift and royal, matching Babylon''s golden head.', 'Daniel 7:4 — first beast like a lion with eagle''s wings.', 'Daniel 7:4', 'The first was like a lion, and had eagle''s wings: I beheld till the wings thereof were plucked, and it was lifted up from the earth, and made stand upon the feet as a man, and a man''s heart was given to it.', 'Wings of speed give way to a humbled, humanized form — Babylon''s pride is checked by the God of heaven.', 1),
  ('daniel-beasts-3', 'daniel-beasts', 'BEAR RAISED UP', 'The second beast that raised itself on one side and had three ribs in its mouth.', 'Daniel 7:5 — bear raised on one side with three ribs.', 'Daniel 7:5', 'And behold another beast, a second, like to a bear, and it raised up itself on one side, and it had three ribs in the mouth of it between the teeth of it: and they said thus unto it, Arise, devour much flesh.', 'Medo-Persia''s lopsided strength and conquests fulfill the second stage of the four-beast vision.', 2),
  ('daniel-beasts-4', 'daniel-beasts', 'LEOPARD WITH FOUR WINGS', 'The third beast of rapid conquest with four heads, pointing to a divided Greek empire.', 'Daniel 7:6 — leopard with four wings and four heads.', 'Daniel 7:6', 'After this I beheld, and lo another, like a leopard, which had upon the back of it four wings of a fowl; the beast had also four heads; and dominion was given to it.', 'Swift as a leopard, Greece under Alexander spreads quickly, then divides into four successor domains.', 3),
  ('daniel-horn-1', 'daniel-horn', 'LITTLE HORN', 'A horn that arises among ten, uprooting three, with eyes like a man and a mouth speaking great things.', 'Daniel 7:8 — another little horn with eyes and a mouth.', 'Daniel 7:8', 'I considered the horns, and, behold, there came up among them another little horn, before whom there were three of the first horns plucked up by the roots: and, behold, in this horn were eyes like the eyes of man, and a mouth speaking great things.', 'A religio-political power emerges after imperial Rome, marked by intelligence, speech, and the displacement of rivals.', 0),
  ('daniel-horn-2', 'daniel-horn', 'SPEAK GREAT WORDS', 'The little horn''s blasphemous claims against the Most High.', 'Daniel 7:25 — speaks great words against the most High.', 'Daniel 7:25', 'And he shall speak great words against the most High, and shall wear out the saints of the most High, and think to change times and laws: and they shall be given into his hand until a time and times and the dividing of time.', 'Blasphemy, persecution of the saints, and attempts to alter divine times and laws identify this power in history and prophecy.', 1),
  ('daniel-horn-3', 'daniel-horn', 'TIME TIMES AND DIVIDING', 'The prophetic period during which the saints are given into the little horn''s hand.', 'Daniel 7:25 — time, times, and the dividing of time.', 'Daniel 7:25', 'And he shall speak great words against the most High, and shall wear out the saints of the most High, and think to change times and laws: and they shall be given into his hand until a time and times and the dividing of time.', 'A fixed prophetic timespan limits oppression; God sets the bounds of the little horn''s dominion.', 2),
  ('daniel-horn-4', 'daniel-horn', 'JUDGMENT WAS SET', 'The heavenly court session that sits and takes away the little horn''s dominion.', 'Daniel 7:26 — the judgment shall sit; dominion taken away.', 'Daniel 7:26', 'But the judgment shall sit, and they shall take away his dominion, to consume and to destroy it unto the end.', 'Heaven''s judgment answers blasphemy with final justice; the horn''s dominion ends under the verdict of God.', 3),
  ('daniel-sanctuary-1', 'daniel-sanctuary', 'TWO THOUSAND THREE HUNDRED DAYS', 'The long prophetic period after which the sanctuary shall be cleansed.', 'Daniel 8:14 — unto two thousand and three hundred days.', 'Daniel 8:14', 'And he said unto me, Unto two thousand and three hundred days; then shall the sanctuary be cleansed.', 'This prophetic span anchors Advent hope in a heavenly Day of Atonement work before the Second Coming.', 0),
  ('daniel-sanctuary-2', 'daniel-sanctuary', 'SANCTUARY BE CLEANSED', 'The climactic phrase of Daniel 8:14 announcing purification of the heavenly sanctuary.', 'Daniel 8:14 — then shall the sanctuary be cleansed.', 'Daniel 8:14', 'And he said unto me, Unto two thousand and three hundred days; then shall the sanctuary be cleansed.', 'Cleansing points to Christ''s priestly ministry removing the record of confessed sin in the true tabernacle.', 1),
  ('daniel-sanctuary-3', 'daniel-sanctuary', 'DAILY SACRIFICE', 'The continual ministry cast down by the little horn in Daniel 8''s vision of the ram and goat.', 'Daniel 8:11 — the daily sacrifice was taken away.', 'Daniel 8:11', 'Yea, he magnified himself even to the prince of the host, and by him the daily sacrifice was taken away, and the place of his sanctuary was cast down.', 'Counterfeit systems obscure Christ''s continual priesthood; the sanctuary truth restores the true ministry.', 2),
  ('daniel-sanctuary-4', 'daniel-sanctuary', 'EVENING AND MORNING', 'The prophetic day unit used when the vision of the daily and the transgression is explained.', 'Daniel 8:26 — vision of the evening and the morning is true.', 'Daniel 8:26', 'And the vision of the evening and the morning which was told is true: wherefore shut thou up the vision; for it shall be for many days.', 'Evening-morning language marks prophetic days; the vision reaches far beyond Daniel''s own lifetime.', 3),
  ('daniel-stand-1', 'daniel-stand', 'MICHAEL STAND UP', 'The great prince who stands for God''s people at the time of unprecedented trouble.', 'Daniel 12:1 — Michael shall stand up, the great prince.', 'Daniel 12:1', 'And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation even to that same time: and at that time thy people shall be delivered, every one that shall be found written in the book.', 'When Michael stands, deliverance comes for those written in the book — after the final crisis of earth''s history.', 0),
  ('daniel-stand-2', 'daniel-stand', 'WRITTEN IN THE BOOK', 'The record that identifies who will be delivered when Michael stands up.', 'Daniel 12:1 — delivered, every one found written in the book.', 'Daniel 12:1', 'And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation even to that same time: and at that time thy people shall be delivered, every one that shall be found written in the book.', 'Salvation is personal and recorded. Only those found written in the book share Michael''s deliverance.', 1),
  ('daniel-stand-3', 'daniel-stand', 'MANY SHALL RUN TO AND FRO', 'The end-time increase of knowledge and earnest searching of prophecy.', 'Daniel 12:4 — many shall run to and fro; knowledge increased.', 'Daniel 12:4', 'But thou, O Daniel, shut up the words, and seal the book, even to the time of the end: many shall run to and fro, and knowledge shall be increased.', 'As the end nears, sealed prophecy opens and diligent study multiplies understanding among the faithful.', 2),
  ('daniel-stand-4', 'daniel-stand', 'WISE SHALL SHINE', 'Those who turn many to righteousness, shining as the brightness of the firmament.', 'Daniel 12:3 — they that be wise shall shine as the firmament.', 'Daniel 12:3', 'And they that be wise shall shine as the brightness of the firmament; and they that turn many to righteousness as the stars for ever and ever.', 'Wisdom in prophecy leads to soul-winning; the reward is everlasting brightness with the redeemed.', 3)
insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('rev-churches-1', 'rev-churches', 'SEVEN CHURCHES', 'The congregations in Asia to whom John is commanded to write the Revelation.', 'Revelation 1:11 — write and send unto the seven churches in Asia.', 'Revelation 1:11', 'Saying, I am Alpha and Omega, the first and the last: and, What thou seest, write in a book, and send it unto the seven churches which are in Asia; unto Ephesus, and unto Smyrna, and unto Pergamos, and unto Thyatira, and unto Sardis, and unto Philadelphia, and unto Laodicea.', 'Seven local churches receive living messages that also map the spiritual eras of Christian history.', 0),
  ('rev-churches-2', 'rev-churches', 'FIRST LOVE', 'What Ephesus left behind, and what Christ calls them to remember and do again.', 'Revelation 2:4 — thou hast left thy first love.', 'Revelation 2:4', 'Nevertheless I have somewhat against thee, because thou hast left thy first love.', 'Orthodoxy without love is incomplete. Christ invites the church to return to the affection of its beginning.', 1),
  ('rev-churches-3', 'rev-churches', 'LAODICEA', 'The lukewarm church that says it is rich yet needs gold, raiment, and eyesalve from Christ.', 'Revelation 3:16 — lukewarm, neither cold nor hot.', 'Revelation 3:16', 'So then because thou art lukewarm, and neither cold nor hot, I will spue thee out of my mouth.', 'End-time self-satisfaction is the danger; Christ''s rebuke is love calling His people to repentance and zeal.', 2),
  ('rev-churches-4', 'rev-churches', 'OPEN DOOR', 'The door Christ sets before Philadelphia that no man can shut.', 'Revelation 3:8 — I have set before thee an open door.', 'Revelation 3:8', 'I know thy works: behold, I have set before thee an open door, and no man can shut it: for thou hast a little strength, and hast kept my word, and hast not denied my name.', 'Mission opportunity and heavenly access open to a faithful remnant who keep His word despite little strength.', 3),
  ('rev-seals-1', 'rev-seals', 'BOOK SEALED', 'The scroll in God''s right hand, sealed with seven seals, that only the Lamb can open.', 'Revelation 5:1 — a book sealed with seven seals.', 'Revelation 5:1', 'And I saw in the right hand of him that sat on the throne a book written within and on the backside, sealed with seven seals.', 'Human history''s sealed decrees open only through Christ''s worthiness as the slain yet risen Lamb.', 0),
  ('rev-seals-2', 'rev-seals', 'WHITE HORSE', 'The first seal''s rider going forth conquering and to conquer.', 'Revelation 6:2 — a white horse; he went forth conquering.', 'Revelation 6:2', 'And I saw, and behold a white horse: and he that sat on him had a bow; and a crown was given unto him: and he went forth conquering, and to conquer.', 'The pure advance of the gospel is pictured as a conquering rider under the first seal.', 1),
  ('rev-seals-3', 'rev-seals', 'SOULS UNDER THE ALTAR', 'The fifth-seal cry of the martyrs asking how long until their blood is avenged.', 'Revelation 6:9 — souls under the altar slain for the word.', 'Revelation 6:9', 'And when he had opened the fifth seal, I saw under the altar the souls of them that were slain for the word of God, and for the testimony which they held:', 'Persecuted saints are not forgotten; their appeal rises until the final vindication of God.', 2),
  ('rev-seals-4', 'rev-seals', 'SIXTH SEAL', 'The seal of cosmic signs — earthquake, darkened sun, falling stars — before the great day.', 'Revelation 6:12 — great earthquake; sun black as sackcloth.', 'Revelation 6:12', 'And I beheld when he had opened the sixth seal, and, lo, there was a great earthquake; and the sun became black as sackcloth of hair, and the moon became as blood;', 'Nature itself signals the nearness of judgment, calling the world to prepare for the Lamb''s day.', 3),
  ('rev-trumpets-1', 'rev-trumpets', 'SEVEN TRUMPETS', 'The series of angel-blown warnings that follow the opening of the seventh seal''s silence.', 'Revelation 8:6 — seven angels with seven trumpets prepared.', 'Revelation 8:6', 'And the seven angels which had the seven trumpets prepared themselves to sound.', 'Trumpets in Scripture summon, warn, and announce war — here they mark successive judgments on a rebellious world.', 0),
  ('rev-trumpets-2', 'rev-trumpets', 'INCENSE WITH PRAYERS', 'What the angel offers with the prayers of the saints upon the golden altar before the throne.', 'Revelation 8:3 — incense with the prayers of all saints.', 'Revelation 8:3', 'And another angel came and stood at the altar, having a golden censer; and there was given unto him much incense, that he should offer it with the prayers of all saints upon the golden altar which was before the throne.', 'Before trumpets sound, intercession and prayer rise with incense — mercy still mingles with judgment.', 1),
  ('rev-trumpets-3', 'rev-trumpets', 'WOE WOE WOE', 'The triple cry of the eagle announcing the last three trumpets upon earth''s inhabitants.', 'Revelation 8:13 — Woe, woe, woe, to the inhabiters of the earth.', 'Revelation 8:13', 'And I beheld, and heard an angel flying through the midst of heaven, saying with a loud voice, Woe, woe, woe, to the inhabiters of the earth by reason of the other voices of the trumpet of the three angels, which are yet to sound!', 'The final three trumpets intensify crisis; heaven itself warns that greater trouble still approaches.', 2),
  ('rev-trumpets-4', 'rev-trumpets', 'MYSTERY OF GOD FINISHED', 'What is completed in the days of the voice of the seventh angel when he begins to sound.', 'Revelation 10:7 — the mystery of God should be finished.', 'Revelation 10:7', 'But in the days of the voice of the seventh angel, when he shall begin to sound, the mystery of God should be finished, as he hath declared to his servants the prophets.', 'The seventh trumpet era closes the prophetic mystery and ushers in the finishing of God''s plan of salvation.', 3),
  ('rev-beast-1', 'rev-beast', 'BEAST FROM THE SEA', 'The composite leopard-bear-lion power that rises from the sea with seven heads and ten horns.', 'Revelation 13:1 — a beast rise up out of the sea.', 'Revelation 13:1', 'And I stood upon the sand of the sea, and saw a beast rise up out of the sea, having seven heads and ten horns, and upon his horns ten crowns, and upon his heads the name of blasphemy.', 'A blasphemous world power unites features of prior empires and receives authority for a limited prophetic period.', 0),
  ('rev-beast-2', 'rev-beast', 'BEAST FROM THE EARTH', 'The second beast with two lamb-like horns that speaks as a dragon.', 'Revelation 13:11 — another beast coming up out of the earth.', 'Revelation 13:11', 'And I beheld another beast coming up out of the earth; and he had two horns like a lamb, and he spake as a dragon.', 'Gentle appearance with dragon speech points to a power that begins with liberty yet ends enforcing tyranny.', 1),
  ('rev-beast-3', 'rev-beast', 'IMAGE OF THE BEAST', 'The structure the earth beast causes to be made, which both speaks and kills dissenters.', 'Revelation 13:15 — image of the beast should both speak.', 'Revelation 13:15', 'And he had power to give life unto the image of the beast, that the image of the beast should both speak, and cause that as many as would not worship the image of the beast should be killed.', 'An image copies the first beast''s principle of enforced religion — the final test of worship for every soul.', 2),
  ('rev-beast-4', 'rev-beast', 'NUMBER OF HIS NAME', 'The number of a man associated with the beast — six hundred threescore and six.', 'Revelation 13:18 — his number is Six hundred threescore and six.', 'Revelation 13:18', 'Here is wisdom. Let him that hath understanding count the number of the beast: for it is the number of a man; and his number is Six hundred threescore and six.', 'Wisdom and understanding are required to identify the beast; Scripture invites careful, prayerful study — not superstition.', 3),
  ('rev-millennium-1', 'rev-millennium', 'THOUSAND YEARS', 'The millennial period during which Satan is bound and the saints reign with Christ.', 'Revelation 20:2 — bound him a thousand years.', 'Revelation 20:2', 'And he laid hold on the dragon, that old serpent, which is the Devil, and Satan, and bound him a thousand years,', 'A fixed thousand-year epoch separates the first resurrection of the just from the final destruction of evil.', 0),
  ('rev-millennium-2', 'rev-millennium', 'FIRST RESURRECTION', 'The blessed rising of those who share in life with Christ at the start of the thousand years.', 'Revelation 20:6 — blessed is he that hath part in the first resurrection.', 'Revelation 20:6', 'Blessed and holy is he that hath part in the first resurrection: on such the second death hath no power, but they shall be priests of God and of Christ, and shall reign with him a thousand years.', 'Participation in the first resurrection means eternal safety from the second death and shared reign with Christ.', 1),
  ('rev-millennium-3', 'rev-millennium', 'SECOND DEATH', 'The final destruction that has no power over those in the first resurrection.', 'Revelation 20:14 — this is the second death.', 'Revelation 20:14', 'And death and hell were cast into the lake of fire. This is the second death.', 'Death itself is destroyed; the second death ends sin permanently for those who refuse the first resurrection''s hope.', 2),
  ('rev-millennium-4', 'rev-millennium', 'BOOK OF LIFE', 'The register opened at the great white throne; those not found written are judged accordingly.', 'Revelation 20:15 — not found written in the book of life.', 'Revelation 20:15', 'And whosoever was not found written in the book of life was cast into the lake of fire.', 'Eternal destiny turns on the book of life — a call to trust Christ now while mercy still invites.', 3)
